  addSender: (senderId, workspaceId) => request('/api/senders', { method: 'POST', body: { senderId, workspaceId } }),
  removeSender: (senderId, workspaceId) => request(`/api/senders/${senderId}${workspaceId ? `?workspace=${workspaceId}` : ''}`, { method: 'DELETE' }),

