  getLeadAssetMatch: (id) => request(`/api/leads/${id}/asset-match`),
  getLeadDistribution: () => request('/api/leads/distribution'),

  importLead: (data) => request('/api/leads/import', { method: 'POST', body: data }),

  // Assets
  getAssets: () => request('/api/assets'),
