  updateCampaign: (id, data) => request(`/api/campaigns/${id}`, { method: 'PATCH', body: data }),
  deleteCampaign: (id) => request(`/api/campaigns/${id}`, { method: 'DELETE' }),

  // Training
  getTrainingScenario: (type) => request(`/api/training/scenario${type ? `?type=${type}` : ''}`),
