  getSettings: () => request('/api/settings'),
  saveAirtableCredentials: (apiKey, baseId) => request('/api/settings/airtable', { method: 'POST', body: { apiKey, baseId } }),
  testAirtableConnection: () => request('/api/settings/test-airtable', { method: 'POST', body: {} }),
  // simulationStart — `situation` (optional) steers the synthesized starter
