  simulationStart: (seniority, stage, situation) => request('/api/training/simulation/start', { method: 'POST', body: { seniority, stage, situation } }),
  // Default behavior: returns BOTH our message and the lead reply in one call
  // (legacy one-step flow). Pass skipLeadReply=true for the two-step flow,
  // where the dashboard pauses after our message so the user can rewrite /
  // edit before generating the lead's response separately.
  // `targetAvatarId` (optional) — when set, the server gates the force-silent
  // override (no random ghosting unless the target is follow_up_after_ghosting)
  // and returns `classifierMismatch: true` when Haiku's avatar !== target.
  simulationStep: (lead, seniority, thread, skipLeadReply = false, targetAvatarId = null) => request('/api/training/simulation/step', { method: 'POST', body: { lead, seniority, thread, skipLeadReply, targetAvatarId } }),
  // Two-step companion to simulationStep — generates ONLY the lead reply,
  // considering whatever rewrites/edits the user made to the thread first.
  // `targetAvatarId` (optional) — when set, the server suppresses the silent
  // outcome unless the target situation IS follow_up_after_ghosting, mirroring
  // the gating in /simulation/step. Without this, ~30% of replies still go silent.
  simulationLeadReply: (lead, thread, targetAvatarId = null) => request('/api/training/simulation/lead-reply', { method: 'POST', body: { lead, thread, targetAvatarId } }),
  simulationGhost: (lead, seniority, thread) => request('/api/training/simulation/ghost', { method: 'POST', body: { lead, seniority, thread } }),

