  // Avatars
  getAvatarAxes: () => request('/api/avatars/axes'),
  getAvatarCoverage: () => request('/api/avatars/coverage'),
  // Row-scoped coverage with the next-gap pointer. Drives the Auto-fill flow:
  // returns `next` = the cell that needs the most help (highest deficit), and
  // `cells` filtered to just the requested seniority row.
  getAvatarCoverageScoped: (seniority) => request(`/api/avatars/coverage/scoped${seniority ? `?seniority=${encodeURIComponent(seniority)}` : ''}`),
  getAvatarExamples: (avatarId, withInjected = false) => request(`/api/avatars/${encodeURIComponent(avatarId)}/examples${withInjected ? '?injected=true' : ''}`),
  setExampleCanonical: (airtableId, isCanonical) => request(`/api/avatars/example/${airtableId}`, { method: 'PATCH', body: { isCanonical } }),
  setExampleAvatar: (airtableId, avatar) => request(`/api/avatars/example/${airtableId}`, { method: 'PATCH', body: { avatar } }),
  updateExample: (airtableId, fields) => request(`/api/avatars/example/${airtableId}`, { method: 'PATCH', body: fields }),
  deleteExample: (airtableId) => request(`/api/avatars/example/${airtableId}`, { method: 'DELETE' }),
  createExample: (avatarId, data) => request(`/api/avatars/${encodeURIComponent(avatarId)}/examples`, { method: 'POST', body: data }),
  addSituation: (name) => request('/api/avatars/axes/situation', { method: 'POST', body: { name } }),
  deleteSituation: (name, force = false) => request(`/api/avatars/axes/situation/${encodeURIComponent(name)}${force ? '?force=true' : ''}`, { method: 'DELETE' }),
  runAvatarMigration: (reclassify = false) => request('/api/avatars/migrate', { method: 'POST', body: { reclassify } }),
  getAvatarMigrationStatus: () => request('/api/avatars/migrate/status'),

  // Horizon (adjacency rules — editable)
  getHorizon: () => request('/api/horizon'),
  updateHorizonAxis: (axis, entries) => request(`/api/horizon/${axis}`, { method: 'PUT', body: { entries } }),
