// Renders the placeholder catalog as clickable chips. Clicking a chip inserts the token
// at the cursor position of the most recently focused textarea (tracked via onMouseDown,
// which fires BEFORE focus moves to the chip — so we capture the textarea state in time).
function PlaceholderReference({ onInsert }) {
  const [flashed, setFlashed] = useState(null);
  const handleClick = (token) => {
    const result = onInsert ? onInsert(token) : null;
    setFlashed({ token, mode: result || 'copied' });
    setTimeout(() => setFlashed(null), 1200);
  };
  return (
    <div style={{ background: '#FFFFFF', border: '1px solid rgba(0,0,0,0.08)', borderRadius: 10, padding: 14, marginBottom: 14 }}>
      <div style={{ fontSize: 11, color: '#9E9E9E', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 8, fontWeight: 600 }}>
        Available placeholders — click to insert at cursor
      </div>
      <div style={{ fontSize: 11, color: '#6B6B6B', marginBottom: 12, lineHeight: 1.5 }}>
        Click a token to insert it into the textarea where your cursor is. If no textarea is focused, the token is copied to your clipboard instead.
        Add a fallback with <code style={{ background: '#FAF9F7', padding: '1px 4px', borderRadius: 3 }}>{`{notes.field | "default text"}`}</code> — examples whose required tokens can't be filled get skipped automatically.
      </div>
      {PLACEHOLDER_CATALOG.map(group => (
        <div key={group.namespace} style={{ marginBottom: 12 }}>
          <div style={{ fontSize: 11, fontWeight: 600, color: group.color, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 6 }}>
            {group.label}
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
            {group.tokens.map(t => {
              const isFlashed = flashed?.token === t.token;
              return (
                <button key={t.token}
                  // onMouseDown runs BEFORE the chip steals focus from the textarea, so we
                  // can read selectionStart while the textarea is still active.
                  onMouseDown={(e) => { e.preventDefault(); handleClick(t.token); }}
                  title={`${t.desc} — e.g. "${t.example}"`}
                  style={{
                    fontSize: 11, padding: '4px 10px', border: `1px solid ${group.color}33`,
                    borderRadius: 12, background: isFlashed ? group.color : group.bg,
                    color: isFlashed ? '#FFFFFF' : group.color,
                    cursor: 'pointer', fontFamily: 'ui-monospace, SFMono-Regular, Menlo, monospace',
                    transition: 'all 0.12s',
                  }}>
                  {isFlashed ? (flashed.mode === 'inserted' ? '✓ inserted' : '✓ copied') : t.token}
                </button>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}

